external_knowledge:
- "Plucked the golden apples" refers to accepting an insurance quote;
- "The magic touch of the orchard guardian (Jerry's discount)" symbolizes the application of Jerry's discount to the insurance rates;
- "The vehicles they’ve driven" refers to the cars associated with the customers, described by their make and model.

- 'lucky customer' refers to a randomly selected customer;
- 'active policy' indicates the policy status must be 'active';
- 'discount applied' means the customer has had a discount recorded in the discounts applied table.

sql:
SELECT customers.name, quotes.before_jerry
FROM quotes
INNER JOIN customers ON quotes.customer_id = customers.customer_id;

SELECT cars.make, cars.model, quotes.before_jerry, quotes.after_jerry
FROM cars
JOIN quotes ON cars.car_id = quotes.car_id;

SELECT quote_id, customer_id
FROM quotes
WHERE quote_status = 'pending';

SELECT discount_name, discount_amount
FROM discounts_offered
WHERE customer_id = 1 AND discount_amount < 10;

SELECT discount_name, SUM(CAST(REPLACE(discount_amount, ',', '') AS REAL)) AS total_discount, COUNT(*) AS total_customers
FROM discounts_offered
GROUP BY discount_name;

SELECT mileage
FROM cars
WHERE car_id = 1;

